const body = $input.first().json.body || {};
const message = (body.message || '').trim();
const session_id = (body.session_id || 'sql-default').trim();

// Health-check: отдаём pong без вызова LLM
if (message === 'ping') {
  return [{json: {valid: 0, error: 'pong'}}];
}

// __AUTH_PATCH_V1__
// === SSO Phase 3: token presence check ===
// Без токена → auth_required, фронт redirect на /login.html
const __token = String((body && body.token) || '').trim();
if (!__token || !/^[a-f0-9]{64}$/.test(__token)) {
  return [{json: {valid: 0, error: 'auth_required', auth_required: true}}];
}


if (!message || message.length < 2) {
  return [{json: {valid: 0, error: 'Введите сообщение'}}];
}

// Защита от SQL-инъекций через session_id
if (!/^[a-zA-Z0-9_-]{3,64}$/.test(session_id)) {
  return [{json: {valid: 0, error: 'session_id содержит недопустимые символы'}}];
}

if (message.length > 100000) {
  return [{json: {valid: 0, error: 'Слишком длинный запрос (максимум 100000 символов)'}}];
}

return [{json: {valid: 1, message: message, session_id: session_id, token: __token}}];

const message = $('Агрегация').first().json.message;
const historyContext = $('Агрегация').first().json.historyContext || '';
const session_id = $('Агрегация').first().json.session_id || 'sql-default';
const lower = message.toLowerCase();

const sqlKeywords = [
  'покажи', 'выведи', 'список', 'найди клиент', 'найди заказ',
  'клиент', 'заказ', 'заказы', 'выручк', 'revenue',
  'таблиц', 'запрос', 'база данных', 'бд', 'базу',
  'select', 'insert', 'update', 'delete', 'sql',
  'добавь', 'удали', 'измени', 'обнови',
  'сколько клиентов', 'сколько заказов', 'сколько записей',
  'статус', 'pending', 'delivered', 'cancelled',
  'город', 'москва', 'питер', 'петербург',
  'email', 'выручка', 'сумма заказ', 'средн',
  'группир', 'сортир', 'отсортируй', 'отфильтруй', 'фильтр',
  'топ ', 'top ', 'первые', 'последние',
  'join', 'объедин', 'связ',
  'аналитик', 'статистик', 'отчёт', 'отчет',
  'за период', 'за месяц', 'за год', 'за неделю',
  'больше чем', 'меньше чем', 'равно',
  'максимальн', 'минимальн', 'итого'
];

let isSQL = false;

for (const kw of sqlKeywords) {
  if (lower.includes(kw)) { isSQL = true; break; }
}

// Если упоминаются данные и есть вопросительный характер
if (!isSQL && message.length > 15) {
  const dataIndicators = ['сколько', 'какие', 'кто', 'где', 'когда', 'чей', 'чья'];
  const dataEntities = ['клиент', 'заказ', 'товар', 'продукт', 'запис', 'строк'];
  const hasQuestion = dataIndicators.some(q => lower.includes(q));
  const hasEntity = dataEntities.some(e => lower.includes(e));
  if (hasQuestion && hasEntity) isSQL = true;
}

if (!isSQL) {
  return [{ json: { message, mode: 'general', historyContext, session_id } }];
}

return [{ json: { message, mode: 'sql', historyContext, session_id } }];

try {
  const raw = $input.first().json;
  if (raw.error) {
    return [{ json: { response: 'Не удалось обработать запрос. Попробуйте ещё раз.' } }];
  }
  const text = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!text) {
    return [{ json: { response: 'Пустой ответ от LLM. Попробуйте ещё раз.' } }];
  }
  return [{ json: { response: text.trim() } }];
} catch(e) {
  return [{ json: { response: 'Ошибка обработки.' } }];
}

// Безопасная очистка SQL от LLM. Принимаем ТОЛЬКО SELECT (whitelist),
// мульти-стейтменты блокируем (`;` где-либо кроме конца).
// DELETE/UPDATE/DROP/etc — всё запрещено, потому что нельзя надёжно отличить
// «легитимный DELETE с WHERE» от «DELETE WHERE 1=1». Если потом понадобится
// мутирующий SQL — заводи отдельного агента с read-write пользователем БД.
try {
  const raw = $input.first().json;

  if (raw.error) {
    return [{json: {query: "SELECT 'GigaChat недоступен. Попробуйте позже.' as error_message;"}}];
  }

  // Безопасный доступ к ответу LLM
  let sql = raw && raw.output && raw.output[0] && raw.output[0].content && raw.output[0].content[0] && raw.output[0].content[0].text;
  if (!sql) {
    return [{json: {query: "SELECT 'Пустой ответ от LLM. Попробуйте ещё раз.' as error_message;"}}];
  }

  // Убираем markdown
  sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

  // Находим начало SQL — допускаем только SELECT или WITH (CTE → SELECT)
  const match = sql.match(/\b(SELECT|WITH|INSERT|UPDATE|DELETE|CREATE|ALTER|DROP|TRUNCATE|GRANT|REVOKE|EXEC|CALL|COPY|VACUUM|ANALYZE)\b/i);
  if (match && match.index > 0) {
    sql = sql.substring(match.index);
  }

  // Удаляем висячую `;` в конце
  sql = sql.replace(/;\s*$/, '');

  // === Защита от multi-statement injection ===
  // Любая `;` в теле (не в конце) означает второй стейтмент. Блокируем.
  // (`;` внутри строковых литералов уже не страшен — node-postgres экранирует,
  // но LLM-генерация не должна так делать вообще.)
  if (sql.includes(';')) {
    return [{json: {query: "SELECT 'Multi-statement SQL заблокирован. Используйте один запрос.' as error_message;"}}];
  }

  // === Whitelist: только SELECT и CTE (WITH ... SELECT) ===
  const firstWord = sql.trim().split(/\s+/)[0].toUpperCase();
  const ALLOWED = ['SELECT', 'WITH'];
  if (!ALLOWED.includes(firstWord)) {
    return [{json: {query: "SELECT '" + firstWord + " заблокирован. Этот агент умеет только SELECT-запросы (read-only).' as error_message;"}}];
  }

  // Дополнительная защита: даже внутри WITH-CTE запрещаем модифицирующие statement'ы
  if (/\b(INSERT|UPDATE|DELETE|DROP|TRUNCATE|ALTER|CREATE|GRANT|REVOKE|COPY|VACUUM|ANALYZE)\b/i.test(sql)) {
    return [{json: {query: "SELECT 'В запросе обнаружен модифицирующий statement. Только SELECT разрешён.' as error_message;"}}];
  }

  // Авто-LIMIT для SELECT и WITH...SELECT (если LIMIT отсутствует)
  if (!/\bLIMIT\b/i.test(sql)) {
    sql += ' LIMIT 50';
  }
  sql += ';';

  return [{json: {query: sql}}];

} catch(e) {
  return [{json: {query: "SELECT 'Не удалось сгенерировать SQL. Переформулируйте вопрос.' as error_message;"}}];
}

try {
